import UIKit

class UniversalLinkHandler {
    static let shared = UniversalLinkHandler()
    
    private init() {}
    
    func handleUniversalLink(_ url: URL) -> Bool {
        guard url.scheme == "https" else {
            return false
        }
        
        let pathComponents = url.pathComponents.filter { !$0.isEmpty }
        
        guard !pathComponents.isEmpty else {
            return false
        }
        
        let rootPath = pathComponents[0]
        
        switch rootPath {
        case "profile":
            handleProfileLink(pathComponents)
        case "payment":
            handlePaymentLink(pathComponents)
        case "admin":
            handleAdminLink(pathComponents)
        default:
            return false
        }
        
        return true
    }
    
    private func handleProfileLink(_ components: [String]) {
        guard components.count >= 2 else { return }
        
        let userId = components[1]
        
        DispatchQueue.main.async {
            if let scene = UIApplication.shared.connectedScenes.first,
               let windowScene = scene as? UIWindowScene,
               let window = windowScene.windows.first {
                
                let storyboard = UIStoryboard(name: "Main", bundle: nil)
                if let profileVC = storyboard.instantiateViewController(withIdentifier: "ProfileViewController") as? ProfileViewController {
                    profileVC.userId = userId
                    window.rootViewController?.pushViewController(profileVC, animated: true)
                }
            }
        }
    }
    
